import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion('gpt-4', { apiKey: process.env.OPENAI_API_KEY })
  }
});

async function processVoiceInput(transcript: string): Promise<string> {
  const plan = kernel.createFunction(
    'voice_agent', 'handle_request',
    `User said: ${transcript}`
  );

  const result = await kernel.invoke(plan);

  // Stream to TTS
  await ttsStream(result.toString());

  return result.toString();
}

async function chainedPlugins(input: string): Promise<string> {
  const start = performance.now();

  // Plugin 1: Intent detection
  const intent = await kernel.invoke('intent_plugin', 'detect', { text: input });

  // Plugin 2: Data lookup
  const data = await Promise.race([
    kernel.invoke('data_plugin', 'lookup', { intent: intent.result }),
    new Promise((_, reject) => 
      setTimeout(() => reject('timeout'), 300)
    )
  ]);

  console.log(`Latency: ${performance.now() - start}ms`);
  return data.result;
}

