from vex_sdk import VexClient
from semantic_kernel import KernelFunction

vex = VexClient(api_key="your-vex-key")

@kernel.register_function()
def voice_response_filter(context: KernelFunction):
    # Vex verification
    verification = vex.verify({
        "response": context.result,
        "checklist": ["appropriateness", "coherence", "safety"],
        "latency_budget": 400
    })

    if verification.passed:
        return context.result
    else:
        return "I need a moment to process that."

# Auto-applies to all kernel functions
kernel.func_manager.register_filter(voice_response_filter)

import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

kernel.addExecutionInterceptor(async (plan, context) => {
  // Vex plan validation
  const planCheck = await vex.verify({
    plan: plan.toJson(),
    useCase: 'voice_agent',
    checks: ['valid_sequence', 'latency_estimate', 'safety'],
    timeout: 50
  });

  if (!planCheck.passed) {
    throw new Error('Invalid plan detected by Vex');
  }

  return context;
});
